func escalationXData(p EscalationPolicyListParams) string {
	return fmt.Sprintf(`{
		showForm: false,
		editId: null,
		formAction: '%s/escalation-policies',
		formData: { name: '', description: '', enabled: true, repeat: false, steps: [] },
		openCreate() {
			this.editId = null;
			this.formAction = '%s/escalation-policies';
			this.formData = { name: '', description: '', enabled: true, repeat: false, steps: [{ delay_minutes: 0, channel_ids: [] }] };
			this.showForm = true;
		},
		openEdit(ep) {
			this.editId = ep.id;
			this.formAction = '%s/escalation-policies/' + ep.id;
			this.formData = {
				name: ep.name,
				description: ep.description,
				enabled: ep.enabled,
				repeat: ep.repeat,
				steps: (ep.steps || []).map(s => ({ delay_minutes: s.delay_minutes, channel_ids: [...s.notification_channel_ids] }))
			};
			if (this.formData.steps.length === 0) this.formData.steps.push({ delay_minutes: 0, channel_ids: [] });
			this.showForm = true;
		},
		addStep() { this.formData.steps.push({ delay_minutes: 0, channel_ids: [] }) },
		removeStep(idx) { this.formData.steps.splice(idx, 1) },
		moveStep(idx, dir) {
			let s = this.formData.steps;
			let t = idx + dir;
			if (t < 0 || t >= s.length) return;
			[s[idx], s[t]] = [s[t], s[idx]];
		},
		toggleChannel(stepIdx, chId) {
			let ids = this.formData.steps[stepIdx].channel_ids;
			let i = ids.indexOf(chId);
			if (i >= 0) ids.splice(i, 1); else ids.push(chId);
		}
	}`, p.BasePath, p.BasePath, p.BasePath)
}

